import { useState } from 'react';

/**
 * ============================================================================
 * ADMIN LAYOUT COMPONENT
 * ============================================================================
 * 
 * PURPOSE:
 * This component provides the permanent layout shell for all Admin pages.
 * It handles ONLY navigation, header controls, and page structure.
 * 
 * RESPONSIBILITIES:
 * - Render fixed sidebar with navigation menu
 * - Render sticky header with controls (org selector, search, user menu)
 * - Render footer with version/status info
 * - Manage active navigation state
 * - Dynamically render child pages based on navigation selection
 * 
 * DOES NOT INCLUDE:
 * - Dashboard business logic (KPIs, charts, etc.)
 * - Data fetching or API calls
 * - Complex state management (only nav state)
 * 
 * FUTURE ENHANCEMENTS:
 * - Replace internal state with React Router
 * - Add real authentication context
 * - Connect to backend for org/user data
 * - Implement notification websocket
 * - Add accessibility keyboard navigation
 */

// ============================================================================
// IMPORT CHILD PAGE COMPONENTS
// ============================================================================
// These would normally come from separate files
// For now, using placeholder components

function AdminDashboard() {
  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold text-gray-900 mb-4">Dashboard Overview</h1>
      <div className="bg-white rounded-lg border border-gray-200 p-8 text-center">
        <p className="text-gray-600">
          📊 AdminDashboard content will render here
        </p>
        <p className="text-sm text-gray-500 mt-2">
          (KPIs, charts, and insights from your existing component)
        </p>
      </div>
    </div>
  );
}

function SystemsOverview() {
  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold text-gray-900 mb-4">Systems Overview</h1>
      <div className="bg-white rounded-lg border border-gray-200 p-8 text-center">
        <p className="text-gray-600">
          💻 Systems table and filters will render here
        </p>
      </div>
    </div>
  );
}

function Decisions() {
  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold text-gray-900 mb-4">Decision Support</h1>
      <div className="bg-white rounded-lg border border-gray-200 p-8 text-center">
        <p className="text-gray-600">
          🎯 AI-powered decision recommendations will render here
        </p>
      </div>
    </div>
  );
}

function Reports() {
  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold text-gray-900 mb-4">Reports & Analytics</h1>
      <div className="bg-white rounded-lg border border-gray-200 p-8 text-center">
        <p className="text-gray-600">
          📈 Custom reports and exports will render here
        </p>
      </div>
    </div>
  );
}

// ============================================================================
// MAIN ADMIN LAYOUT COMPONENT
// ============================================================================

function AdminLayout() {
  // ===== NAVIGATION STATE =====
  // This controls which child page is currently displayed
  // TODO: Replace with React Router when implementing routing
  const [activeNav, setActiveNav] = useState('dashboard');
  
  // ===== UI CONTROL STATES =====
  const [userMenuOpen, setUserMenuOpen] = useState(false);
  const [orgSelectorOpen, setOrgSelectorOpen] = useState(false);
  const [timeRangeOpen, setTimeRangeOpen] = useState(false);
  
  // ===== DUMMY DATA =====
  // TODO: Replace with API calls to backend
  const organizations = [
    { id: 'global', name: 'Global View' },
    { id: 'na', name: 'North America' },
    { id: 'emea', name: 'EMEA' },
    { id: 'apac', name: 'APAC' }
  ];
  
  const timeRanges = [
    { id: '24h', label: 'Last 24 Hours' },
    { id: '7d', label: 'Last 7 Days' },
    { id: '30d', label: 'Last 30 Days' },
    { id: '90d', label: 'Last 90 Days' }
  ];
  
  const [selectedOrg, setSelectedOrg] = useState('global');
  const [selectedTimeRange, setSelectedTimeRange] = useState('7d');
  const [searchQuery, setSearchQuery] = useState('');
  
  // Navigation menu configuration
  const navItems = [
    { 
      id: 'dashboard', 
      label: 'Dashboard', 
      icon: '📊'
    },
    { 
      id: 'systems', 
      label: 'Systems', 
      icon: '💻'
    },
    { 
      id: 'decisions', 
      label: 'Decisions', 
      icon: '🎯'
    },
    { 
      id: 'reports', 
      label: 'Reports', 
      icon: '📈'
    }
  ];
  
  // ===== RENDER CHILD PAGE =====
  // Based on activeNav state, render appropriate component
  // TODO: Replace with <Outlet /> when using React Router
  const renderContent = () => {
    switch(activeNav) {
      case 'dashboard':
        return <AdminDashboard />;
      case 'systems':
        return <SystemsOverview />;
      case 'decisions':
        return <Decisions />;
      case 'reports':
        return <Reports />;
      default:
        return <AdminDashboard />;
    }
  };

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden">
      
      {/* ================================================================
          LEFT SIDEBAR - NAVIGATION
          ================================================================
          Fixed width sidebar with branding and navigation menu
          TODO: Add collapse/expand functionality for mobile
      */}
      <aside className="w-64 bg-gray-900 text-white flex flex-col flex-shrink-0">
        
        {/* BRANDING SECTION */}
        <div className="p-6 border-b border-gray-800">
          <div className="flex items-center gap-3">
            {/* Logo Placeholder */}
            <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center">
              <span className="text-xl font-bold">M</span>
            </div>
            <div>
              <h1 className="text-lg font-bold">MaintenanceAI</h1>
              <p className="text-xs text-gray-400">Intelligence Platform</p>
            </div>
          </div>
        </div>
        
        {/* NAVIGATION MENU */}
        <nav className="flex-1 overflow-y-auto py-4">
          <ul className="space-y-1 px-3">
            {navItems.map((item) => (
              <li key={item.id}>
                <button
                  onClick={() => setActiveNav(item.id)}
                  className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 ${
                    activeNav === item.id
                      ? 'bg-blue-600 text-white shadow-lg'
                      : 'text-gray-300 hover:bg-gray-800 hover:text-white'
                  }`}
                >
                  <span className="text-xl">{item.icon}</span>
                  <span className="font-medium">{item.label}</span>
                </button>
              </li>
            ))}
          </ul>
        </nav>
        
        {/* SIDEBAR FOOTER - VERSION INFO */}
        <div className="p-4 border-t border-gray-800">
          <div className="text-xs text-gray-500">
            <div className="flex items-center gap-2 mb-2">
              <div className="w-2 h-2 bg-green-500 rounded-full"></div>
              <span>Agent Connected</span>
            </div>
            <p>Platform v1.0.0</p>
          </div>
        </div>
      </aside>

      {/* ================================================================
          RIGHT SIDE - HEADER + CONTENT + FOOTER
          ================================================================
      */}
      <div className="flex-1 flex flex-col overflow-hidden">
        
        {/* ================================================================
            STICKY HEADER
            ================================================================
            Contains org selector, search, and user controls
            TODO: Connect to real auth context and org management API
        */}
        <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10 shadow-sm">
          
          {/* LEFT SECTION - ORG & TIME SELECTORS */}
          <div className="flex items-center gap-4">
            
            {/* Organization Selector */}
            <div className="relative">
              <button
                onClick={() => setOrgSelectorOpen(!orgSelectorOpen)}
                className="flex items-center gap-2 px-4 py-2 bg-gray-50 border border-gray-300 rounded-lg hover:bg-gray-100 transition-colors"
              >
                <span className="text-sm font-medium text-gray-700">
                  {organizations.find(o => o.id === selectedOrg)?.name}
                </span>
                <span className="text-gray-500">▼</span>
              </button>
              
              {/* Dropdown */}
              {orgSelectorOpen && (
                <div className="absolute top-full left-0 mt-2 w-56 bg-white border border-gray-200 rounded-lg shadow-lg z-20">
                  {organizations.map((org) => (
                    <button
                      key={org.id}
                      onClick={() => {
                        setSelectedOrg(org.id);
                        setOrgSelectorOpen(false);
                        // TODO: Fetch data for selected org
                        console.log('Fetch data for:', org.name);
                      }}
                      className={`w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors first:rounded-t-lg last:rounded-b-lg ${
                        selectedOrg === org.id ? 'bg-blue-50 text-blue-700 font-semibold' : 'text-gray-700'
                      }`}
                    >
                      {org.name}
                    </button>
                  ))}
                </div>
              )}
            </div>
            
            {/* Time Range Selector */}
            <div className="relative">
              <button
                onClick={() => setTimeRangeOpen(!timeRangeOpen)}
                className="flex items-center gap-2 px-4 py-2 bg-gray-50 border border-gray-300 rounded-lg hover:bg-gray-100 transition-colors"
              >
                <span className="text-sm font-medium text-gray-700">
                  {timeRanges.find(t => t.id === selectedTimeRange)?.label}
                </span>
                <span className="text-gray-500">▼</span>
              </button>
              
              {/* Dropdown */}
              {timeRangeOpen && (
                <div className="absolute top-full left-0 mt-2 w-48 bg-white border border-gray-200 rounded-lg shadow-lg z-20">
                  {timeRanges.map((range) => (
                    <button
                      key={range.id}
                      onClick={() => {
                        setSelectedTimeRange(range.id);
                        setTimeRangeOpen(false);
                        // TODO: Refresh data with new time range
                        console.log('Update time range:', range.label);
                      }}
                      className={`w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors first:rounded-t-lg last:rounded-b-lg ${
                        selectedTimeRange === range.id ? 'bg-blue-50 text-blue-700 font-semibold' : 'text-gray-700'
                      }`}
                    >
                      {range.label}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
          
          {/* CENTER SECTION - SEARCH BAR */}
          <div className="flex-1 max-w-xl mx-8">
            <div className="relative">
              <input
                type="text"
                placeholder="Search system ID or owner..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    // TODO: Trigger search API call
                    console.log('Search for:', searchQuery);
                  }
                }}
                className="w-full px-4 py-2 pl-10 bg-gray-50 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              />
              <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">
                🔍
              </span>
            </div>
          </div>
          
          {/* RIGHT SECTION - NOTIFICATIONS & USER MENU */}
          <div className="flex items-center gap-4">
            
            {/* Notification Bell */}
            <button className="relative p-2 hover:bg-gray-100 rounded-lg transition-colors">
              <span className="text-xl">🔔</span>
              {/* Notification Badge */}
              <span className="absolute top-1 right-1 w-5 h-5 bg-red-500 text-white text-xs font-bold rounded-full flex items-center justify-center">
                3
              </span>
            </button>
            
            {/* User Menu */}
            <div className="relative">
              <button
                onClick={() => setUserMenuOpen(!userMenuOpen)}
                className="flex items-center gap-2 p-2 hover:bg-gray-100 rounded-lg transition-colors"
              >
                {/* User Avatar with Initials */}
                <div className="w-9 h-9 bg-blue-600 text-white rounded-full flex items-center justify-center font-semibold">
                  AD
                </div>
                <span className="text-gray-500">▼</span>
              </button>
              
              {/* Dropdown Menu */}
              {userMenuOpen && (
                <div className="absolute top-full right-0 mt-2 w-56 bg-white border border-gray-200 rounded-lg shadow-lg z-20">
                  <div className="px-4 py-3 border-b border-gray-200">
                    <p className="text-sm font-semibold text-gray-900">Admin User</p>
                    <p className="text-xs text-gray-500">admin@company.com</p>
                  </div>
                  
                  <button
                    onClick={() => {
                      setUserMenuOpen(false);
                      console.log('Navigate to: Profile');
                    }}
                    className="w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors text-sm text-gray-700"
                  >
                    👤 Profile
                  </button>
                  
                  <button
                    onClick={() => {
                      setUserMenuOpen(false);
                      console.log('Navigate to: Settings');
                    }}
                    className="w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors text-sm text-gray-700"
                  >
                    ⚙️ Settings
                  </button>
                  
                  <div className="border-t border-gray-200">
                    <button
                      onClick={() => {
                        setUserMenuOpen(false);
                        // TODO: Implement logout logic
                        console.log('Logout');
                      }}
                      className="w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors text-sm text-red-600 font-medium rounded-b-lg"
                    >
                      🚪 Logout
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* ================================================================
            MAIN CONTENT AREA
            ================================================================
            Scrollable container that renders child pages dynamically
            TODO: Replace renderContent() with <Outlet /> when using React Router
        */}
        <main className="flex-1 overflow-y-auto">
          <div className="max-w-[1600px] mx-auto">
            {renderContent()}
          </div>
        </main>

        {/* ================================================================
            FOOTER
            ================================================================
            Subtle footer with platform info and status
        */}
        <footer className="bg-white border-t border-gray-200 px-6 py-4">
          <div className="max-w-[1600px] mx-auto flex items-center justify-between text-sm text-gray-600">
            <div className="flex items-center gap-6">
              <span>© 2025 Company Name</span>
              <span className="text-gray-400">|</span>
              <span>Platform v1.0.0</span>
              <span className="text-gray-400">|</span>
              <span className="px-2 py-1 bg-green-100 text-green-700 rounded text-xs font-semibold">
                Production
              </span>
            </div>
            
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
              <span className="text-xs">All agents operational</span>
            </div>
          </div>
        </footer>
      </div>
    </div>
  );
}

export default AdminLayout;
